class Solution:
    def lengthOfLongestSubstring(self, story: str) -> int:
        # 批改：去首尾空格，中间连续空格压成一个
        s = story.strip(" ")
        if not s:
            return 0
        parts = []
        i = 0
        while i < len(s):
            if s[i] == " ":
                if parts:
                    parts.append(" ")
                while i < len(s) and s[i] == " ":
                    i += 1
            else:
                parts.append(s[i])
                i += 1
        t = "".join(parts).rstrip(" ")

        # 滑动窗口：键为小写字符，记录最近下标
        last = {}
        left = 0
        best = 0
        for right, ch in enumerate(t):
            key = ch.lower()
            if key in last and last[key] >= left:
                left = last[key] + 1
            last[key] = right
            best = max(best, right - left + 1)
        return best
```

```java
public class Solution {
    private String normalize(String story) {
        int a = 0, b = story.length();
        while (a < b && story.charAt(a) == ' ') a++;
        while (b > a && story.charAt(b - 1) == ' ') b--;
        String s = story.substring(a, b);
        if (s.isEmpty()) return "";
        StringBuilder out = new StringBuilder();
        for (int i = 0; i < s.length();) {
            if (s.charAt(i) == ' ') {
                if (out.length() > 0) out.append(' ');
                while (i < s.length() && s.charAt(i) == ' ') i++;
            } else {
                out.append(s.charAt(i++));
            }
        }
        while (out.length() > 0 && out.charAt(out.length() - 1) == ' ')
            out.setLength(out.length() - 1);
        return out.toString();
    }

    public int lengthOfLongestSubstring(String story) {
        String t = normalize(story);
        if (t.isEmpty()) return 0;
        java.util.Map<Character, Integer> last = new java.util.HashMap<>();
        int left = 0, best = 0;
        for (int right = 0; right < t.length(); right++) {
            char key = Character.toLowerCase(t.charAt(right));
            Integer prev = last.get(key);
            // 窗口内已有同字符（忽略大小写），收缩左边界
            if (prev != null && prev >= left) left = prev + 1;
            last.put(key, right);
            best = Math.max(best, right - left + 1);
        }
        return best;
    }
}
