#include <algorithm>
#include <cctype>
#include <string>
#include <unordered_map>

using namespace std;

class Solution {
public:
    string normalize(const string& story) {
        size_t a = 0, b = story.size();
        while (a < b && story[a] == ' ') a++;
        while (b > a && story[b - 1] == ' ') b--;
        string s = story.substr(a, b - a);
        if (s.empty()) return "";
        string out;
        for (size_t i = 0; i < s.size();) {
            if (s[i] == ' ') {
                if (!out.empty()) out.push_back(' ');
                while (i < s.size() && s[i] == ' ') i++;
            } else {
                out.push_back(s[i++]);
            }
        }
        while (!out.empty() && out.back() == ' ') out.pop_back();
        return out;
    }

    int lengthOfLongestSubstring(string story) {
        string t = normalize(story);
        if (t.empty()) return 0;
        unordered_map<char, int> last;  // 小写键 -> 该字符最近下标
        int left = 0, best = 0;
        for (int right = 0; right < (int)t.size(); right++) {
            char key = (char)tolower((unsigned char)t[right]);
            unordered_map<char, int>::iterator it = last.find(key);
            // 窗口内已有同字符（忽略大小写），左边界跳到冲突位置之后
            if (it != last.end() && it->second >= left)
                left = it->second + 1;
            last[key] = right;
            best = max(best, right - left + 1);
        }
        return best;
    }
};
