/**
 * @param {string} story 原始字符串
 * @return {number} 批改后最长无重复字符子串的长度
 */
var lengthOfLongestSubstring = function(story) {
    // 1. 批改：去首尾空格，连续空格压缩为一个
    var cleaned = "";
    var inSpace = false;
    var trimmed = story.trim();
    for (var i = 0; i < trimmed.length; i++) {
        var ch = trimmed[i];
        if (ch === ' ') {
            if (!inSpace) {
                cleaned += ' ';
                inSpace = true;
            }
        } else {
            cleaned += ch;
            inSpace = false;
        }
    }

    // 2. 滑动窗口：忽略大小写，找最长无重复子串
    var last = {};
    var maxLen = 0;
    var left = 0;
    for (var i = 0; i < cleaned.length; i++) {
        var key = cleaned[i].toLowerCase();
        // 窗口内已有同字符（忽略大小写），收缩左边界
        if (last[key] !== undefined && last[key] >= left) {
            left = last[key] + 1;
        }
        last[key] = i;
        maxLen = Math.max(maxLen, i - left + 1);
    }
    return maxLen;
};
