```c
#include <string.h>
#include <ctype.h>

/**
 * @param story 原始字符串
 * @return 批改后最长无重复字符子串的长度
 */
int lengthOfLongestSubstring(char* story) {
    // 1. 批改：去首尾空格，连续空格压缩为一个
    char cleaned[2005];
    int clen = 0;
    int inSpace = 0;
    int len = strlen(story);

    // 找到首尾非空格边界
    int start = 0;
    while (start < len && story[start] == ' ') start++;
    int end = len - 1;
    while (end >= start && story[end] == ' ') end--;

    // 从 start 到 end 构建清理后的字符串
    for (int i = start; i <= end; i++) {
        if (story[i] == ' ') {
            if (!inSpace) {
                cleaned[clen++] = ' ';
                inSpace = 1;
            }
        } else {
            cleaned[clen++] = story[i];
            inSpace = 0;
        }
    }
    cleaned[clen] = '\0';

    // 2. 滑动窗口：忽略大小写，找最长无重复子串
    int last[256];
    for (int i = 0; i < 256; i++) last[i] = -1;

    int maxLen = 0;
    int left = 0;
    for (int i = 0; i < clen; i++) {
        unsigned char key = tolower((unsigned char)cleaned[i]);
        // 窗口内已有同字符（忽略大小写），收缩左边界
        if (last[key] >= left) {
            left = last[key] + 1;
        }
        last[key] = i;
        int curLen = i - left + 1;
        if (curLen > maxLen) maxLen = curLen;
    }
    return maxLen;
}
